    TOOLS.extend(AGENT_TOOLS)
    _TOOL_HANDLERS.update(_AGENT_TOOL_HANDLERS)
except Exception:  # noqa: BLE001
    logger.debug("Agent tools not available (missing agent extras)")



# ---------------------------------------------------------------------------
# Server factory
# ---------------------------------------------------------------------------

def create_server() -> Server:
    server = Server("GoldenCheck")

    @server.list_tools()
    async def list_tools() -> list[Tool]:
        return TOOLS

    @server.call_tool()
    async def call_tool(name: str, arguments: dict) -> list[TextContent]:
        handler = _TOOL_HANDLERS.get(name)
        if handler is None:
            result = {"error": f"Unknown tool: {name}"}
        else:
            try:
                result = handler(arguments)
            except Exception as exc:
                logger.exception("Tool %s failed", name)
                result = {"error": str(exc)}

        return [TextContent(type="text", text=json.dumps(result, indent=2, default=str))]

    return server


async def run_server() -> None:
    server = create_server()
    async with stdio_server() as (read_stream, write_stream):
        await server.run(read_stream, write_stream, server.create_initialization_options())


def run_server_http(host: str = "0.0.0.0", port: int = 8100) -> None:
    """Run the MCP server over Streamable HTTP (for Railway / remote deployment)."""
    import contextlib
    from collections.abc import AsyncIterator

    import uvicorn
    from starlette.applications import Starlette
    from starlette.responses import JSONResponse
    from starlette.routing import Mount, Route
    from mcp.server.streamable_http_manager import StreamableHTTPSessionManager

    server = create_server()
    session_manager = StreamableHTTPSessionManager(
        app=server,
        json_response=False,
        stateless=False,
    )

    @contextlib.asynccontextmanager
    async def lifespan(app: Starlette) -> AsyncIterator[None]:
        async with session_manager.run():
            yield

    async def server_card(request):
        return JSONResponse({
            "name": "GoldenCheck",
            "description": "Data validation that discovers rules from your data — no hand-written checks needed. Profiles columns, detects quality issues, scores confidence. 19 MCP tools for scanning, validating, profiling, auto-configuring, and explaining findings. DQBench Score: 88.40. Built on Polars, 482K rows/sec.",
            "homepage": "https://github.com/<redacted-word>/goldencheck",
            "iconUrl": "https://avatars.githubusercontent.com/u/192581748"
        })

    starlette_app = Starlette(
        debug=False,
        routes=[
            Route("/.well-known/mcp/server-card.json", server_card),
            Mount("/mcp", app=session_manager.handle_request),
        ],
        lifespan=lifespan,
    )

    logger.info("Starting MCP HTTP server on %s:%s", host, port)
    uvicorn.run(starlette_app, host=host, port=port)

