try:
    from goldencheck.mcp.agent_tools import AGENT_TOOLS, _AGENT_TOOL_HANDLERS

    TOOLS.extend(AGENT_TOOLS)
    _TOOL_HANDLERS.update(_AGENT_TOOL_HANDLERS)
except Exception:  # noqa: BLE001
    logger.debug("Agent tools not available (missing agent extras)")



# ---------------------------------------------------------------------------
# Server factory
# ---------------------------------------------------------------------------

def create_server() -> Server:
    server = Server("GoldenCheck")

    @server.list_tools()
    async def list_tools() -> list[Tool]:
        return TOOLS

    @server.call_tool()
    async def call_tool(name: str, arguments: dict) -> list[TextContent]:
        handler = _TOOL_HANDLERS.get(name)
        if handler is None:
            result = {"error": f"Unknown tool: {name}"}
        else:
            try:
                result = handler(arguments)
            except Exception as exc:
                logger.exception("Tool %s failed", name)
                result = {"error": str(exc)}

        return [TextContent(type="text", text=json.dumps(result, indent=2, default=str))]

    return server


async def run_server() -> None:
    server = create_server()
    async with stdio_server() as (read_stream, write_stream):
        await server.run(read_stream, write_stream, server.create_initialization_options())


def run_server_http(host: str = "0.0.0.0", port: int = 8100) -> None:
    """Run the MCP server over Streamable HTTP (for Railway / remote deployment)."""
    import contextlib
    from collections.abc import AsyncIterator

    import uvicorn
    from starlette.applications import Starlette
    from starlette.responses import JSONResponse
    from starlette.routing import Mount, Route
    from mcp.server.streamable_http_manager import StreamableHTTPSessionManager

    server = create_server()
